import{_ as l,o as e,c as i,ak as r,aq as t}from"./chunks/framework.BZTYhN8l.js";const b=JSON.parse('{"title":"分层思想","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/初识计算机网络/分层思想.md","filePath":"计算机网络/初识计算机网络/分层思想.md","lastUpdated":1775045546000}'),h={name:"计算机网络/初识计算机网络/分层思想.md"};function d(o,a,n,p,s,c){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="分层思想" tabindex="-1">分层思想 <a class="header-anchor" href="#分层思想" aria-label="Permalink to “分层思想”">​</a></h1><h2 id="一、仅有-http-协议头还不够" tabindex="-1">一、仅有 HTTP 协议头还不够 <a class="header-anchor" href="#一、仅有-http-协议头还不够" aria-label="Permalink to “一、仅有 HTTP 协议头还不够”">​</a></h2><p>在前面的分析中，我们已经知道：</p><ul><li>数据在发送前会被封装</li><li>在原始数据（Body）前添加 <strong>协议头（Header）</strong></li><li>形成一个完整的 <strong>协议数据单元（PDU）</strong></li></ul><p>例如：</p><p>[ HTTP Header | Body ]</p><p>但问题来了：</p><p>👉 <strong>这样就可以直接发送了吗？答案：不行</strong></p><h2 id="二、通信的本质-进程与进程之间通信" tabindex="-1">二、通信的本质：进程与进程之间通信 <a class="header-anchor" href="#二、通信的本质-进程与进程之间通信" aria-label="Permalink to “二、通信的本质：进程与进程之间通信”">​</a></h2><p>虽然我们常说：</p><blockquote><p>主机 A 和 主机 B 通信</p></blockquote><p>但实际上：</p><blockquote><p>❗真正通信的是 <strong>进程（Process）</strong></p></blockquote><h3 id="什么是进程" tabindex="-1">什么是进程？ <a class="header-anchor" href="#什么是进程" aria-label="Permalink to “什么是进程？”">​</a></h3><ul><li>正在运行的程序（在内存中，被 CPU 执行）</li><li>例如： <ul><li>浏览器（发送请求）</li><li>Web 服务器（接收请求）</li></ul></li></ul><p>📌 通信模型：</p><p>浏览器进程（A主机） ←→ Web服务器进程（B主机）</p><h2 id="三、新问题-如何标识-哪个进程" tabindex="-1">三、新问题：如何标识“哪个进程”？ <a class="header-anchor" href="#三、新问题-如何标识-哪个进程" aria-label="Permalink to “三、新问题：如何标识“哪个进程”？”">​</a></h2><p>当前问题：</p><p>👉 数据发过去了，但 <strong>不知道交给哪个进程处理</strong></p><h3 id="解决方案-端口号-port" tabindex="-1">解决方案：端口号（Port） <a class="header-anchor" href="#解决方案-端口号-port" aria-label="Permalink to “解决方案：端口号（Port）”">​</a></h3><ul><li>端口号 = 进程的标识符（逻辑）</li><li>操作系统维护：</li></ul><p>进程 ←→ 端口号（唯一对应）</p><h3 id="示例" tabindex="-1">示例： <a class="header-anchor" href="#示例" aria-label="Permalink to “示例：”">​</a></h3><table tabindex="0"><thead><tr><th>进程</th><th>端口号</th></tr></thead><tbody><tr><td>浏览器</td><td>52345</td></tr><tr><td>Web服务器</td><td>80</td></tr></tbody></table><h2 id="四、错误设计-把端口号写进-http-头" tabindex="-1">四、错误设计：把端口号写进 HTTP 头？ <a class="header-anchor" href="#四、错误设计-把端口号写进-http-头" aria-label="Permalink to “四、错误设计：把端口号写进 HTTP 头？”">​</a></h2><p>直觉做法：</p><p>HTTP Header:</p><ul><li>srcPort: xxx</li><li>dstPort: 80</li></ul><p>❌ 问题：</p><ul><li>不止 HTTP 需要端口号</li><li>FTP / DNS / SMTP 都需要</li><li>会导致： <ul><li>重复代码</li><li>冗余设计</li><li>协议耦合严重</li></ul></li></ul><h2 id="五、正确设计-抽象出-传输层协议" tabindex="-1">五、正确设计：抽象出“传输层协议” <a class="header-anchor" href="#五、正确设计-抽象出-传输层协议" aria-label="Permalink to “五、正确设计：抽象出“传输层协议””">​</a></h2><p><img src="'+t+'" alt="alt text"></p><p>类似软件工程中的：</p><blockquote><p>❗“提取公共逻辑”</p></blockquote><p>👉 网络中做法：</p><ul><li>把“端口功能”抽出来</li><li>形成新的协议层</li></ul><h3 id="这个协议就是" tabindex="-1">这个协议就是： <a class="header-anchor" href="#这个协议就是" aria-label="Permalink to “这个协议就是：”">​</a></h3><ul><li><strong>TCP</strong></li><li><strong>UDP</strong></li></ul><h2 id="六、封装过程-分层体现" tabindex="-1">六、封装过程（分层体现） <a class="header-anchor" href="#六、封装过程-分层体现" aria-label="Permalink to “六、封装过程（分层体现）”">​</a></h2><h3 id="_1️⃣-应用层-http" tabindex="-1">1️⃣ 应用层（HTTP） <a class="header-anchor" href="#_1️⃣-应用层-http" aria-label="Permalink to “1️⃣ 应用层（HTTP）”">​</a></h3><p>[ HTTP Header | Body ]</p><p>↓</p><h3 id="_2️⃣-传输层-tcp" tabindex="-1">2️⃣ 传输层（TCP） <a class="header-anchor" href="#_2️⃣-传输层-tcp" aria-label="Permalink to “2️⃣ 传输层（TCP）”">​</a></h3><ul><li>把 HTTP 整体当作数据（Body）</li><li>再加一层头</li></ul><p>[ TCP Header (端口号) | HTTP Header | Body ]</p><p>📌 TCP Header 包含：</p><ul><li>源端口（src port）</li><li>目的端口（dst port）</li></ul><h2 id="七、接收端的解封装过程" tabindex="-1">七、接收端的解封装过程 <a class="header-anchor" href="#七、接收端的解封装过程" aria-label="Permalink to “七、接收端的解封装过程”">​</a></h2><h3 id="步骤" tabindex="-1">步骤： <a class="header-anchor" href="#步骤" aria-label="Permalink to “步骤：”">​</a></h3><ol><li>接收 TCP 数据</li><li>解析 TCP Header，找到目标端口（如 80 的进程）</li><li>定位进程（Web服务器，必须有 HTTP 协议能力）</li><li>去掉 TCP Header</li><li>把数据交给 HTTP 协议处理</li><li>HTTP 再解析 Header</li><li>得到最终原始数据</li></ol><h2 id="八、为什么需要源端口" tabindex="-1">八、为什么需要源端口？ <a class="header-anchor" href="#八、为什么需要源端口" aria-label="Permalink to “八、为什么需要源端口？”">​</a></h2><p>问题：</p><blockquote><p>只传目标端口不行吗？</p></blockquote><p>答案：❌ 不行</p><h3 id="原因" tabindex="-1">原因： <a class="header-anchor" href="#原因" aria-label="Permalink to “原因：”">​</a></h3><p>👉 用于“回信”</p><p>客户端 → 服务器： src: 52345 dst: 80</p><p>服务器 → 客户端： src: 80 dst: 52345</p><p>📌 源端口 = “回信地址”</p><h2 id="九、分层思想-核心" tabindex="-1">九、分层思想（核心） <a class="header-anchor" href="#九、分层思想-核心" aria-label="Permalink to “九、分层思想（核心）”">​</a></h2><h3 id="典型分层结构" tabindex="-1">典型分层结构： <a class="header-anchor" href="#典型分层结构" aria-label="Permalink to “典型分层结构：”">​</a></h3><p>应用层：HTTP / FTP / DNS ↓ 传输层：TCP / UDP ↓ 网络层：IP</p><h2 id="十、各层作用总结" tabindex="-1">十、各层作用总结 <a class="header-anchor" href="#十、各层作用总结" aria-label="Permalink to “十、各层作用总结”">​</a></h2><h3 id="_1️⃣-应用层" tabindex="-1">1️⃣ 应用层 <a class="header-anchor" href="#_1️⃣-应用层" aria-label="Permalink to “1️⃣ 应用层”">​</a></h3><ul><li>面向用户</li><li>定义数据格式（HTTP / JSON 等）</li></ul><h3 id="_2️⃣-传输层-tcp-udp" tabindex="-1">2️⃣ 传输层（TCP / UDP） <a class="header-anchor" href="#_2️⃣-传输层-tcp-udp" aria-label="Permalink to “2️⃣ 传输层（TCP / UDP）”">​</a></h3><p>👉 提供：</p><ul><li><strong>进程 → 进程通信（端到端）</strong></li></ul><h4 id="tcp" tabindex="-1">TCP： <a class="header-anchor" href="#tcp" aria-label="Permalink to “TCP：”">​</a></h4><ul><li>可靠传输（确认、重传、顺序）</li></ul><h4 id="udp" tabindex="-1">UDP： <a class="header-anchor" href="#udp" aria-label="Permalink to “UDP：”">​</a></h4><ul><li>不可靠（快、无连接）</li></ul><h3 id="_3️⃣-网络层-ip" tabindex="-1">3️⃣ 网络层（IP） <a class="header-anchor" href="#_3️⃣-网络层-ip" aria-label="Permalink to “3️⃣ 网络层（IP）”">​</a></h3><p>👉 提供：</p><ul><li><strong>主机 → 主机通信</strong></li></ul><p>解决问题：</p><ul><li>数据从哪台机器 → 到哪台机器</li></ul><h2 id="十一、为什么要分层" tabindex="-1">十一、为什么要分层？ <a class="header-anchor" href="#十一、为什么要分层" aria-label="Permalink to “十一、为什么要分层？”">​</a></h2><h3 id="优点一-降低复杂度" tabindex="-1">优点一：降低复杂度 <a class="header-anchor" href="#优点一-降低复杂度" aria-label="Permalink to “优点一：降低复杂度”">​</a></h3><p>❌ 不分层：</p><ul><li>所有逻辑混在一起</li><li>极其复杂</li></ul><p>✅ 分层：</p><ul><li>各层职责清晰</li><li>易维护</li></ul><h3 id="优点二-问题隔离" tabindex="-1">优点二：问题隔离 <a class="header-anchor" href="#优点二-问题隔离" aria-label="Permalink to “优点二：问题隔离”">​</a></h3><ul><li>哪一层出问题 → 修哪一层</li><li>不影响其他层</li></ul><h3 id="优点三-可独立演化" tabindex="-1">优点三：可独立演化 <a class="header-anchor" href="#优点三-可独立演化" aria-label="Permalink to “优点三：可独立演化”">​</a></h3><h4 id="示例-1" tabindex="-1">示例： <a class="header-anchor" href="#示例-1" aria-label="Permalink to “示例：”">​</a></h4><ul><li>IPv4 → IPv6</li></ul><p>👉 不影响：</p><ul><li>TCP</li><li>HTTP</li></ul><p>📌 原因：</p><blockquote><p>上层只关心“服务”，不关心实现</p></blockquote><h2 id="十二、核心总结" tabindex="-1">十二、核心总结 <a class="header-anchor" href="#十二、核心总结" aria-label="Permalink to “十二、核心总结”">​</a></h2><h3 id="数据传输完整流程" tabindex="-1">数据传输完整流程： <a class="header-anchor" href="#数据传输完整流程" aria-label="Permalink to “数据传输完整流程：”">​</a></h3><p>应用层（HTTP） ↓ 传输层（TCP：加端口） ↓ 网络层（IP：找主机） ↓ 发送 ↓ 接收端逐层解封装</p><h3 id="核心概念记忆" tabindex="-1">核心概念记忆： <a class="header-anchor" href="#核心概念记忆" aria-label="Permalink to “核心概念记忆：”">​</a></h3><ul><li>协议 = 约定</li><li>端口 = 进程标识</li><li>TCP/UDP = 解决进程通信</li><li>IP = 解决主机通信</li><li>分层 = 降低复杂度 + 解耦</li></ul><h2 id="✅-一句话总结" tabindex="-1">✅ 一句话总结 <a class="header-anchor" href="#✅-一句话总结" aria-label="Permalink to “✅ 一句话总结”">​</a></h2><blockquote><p>计算机网络的本质：<strong>通过分层协议，实现从一个进程到另一个进程的可靠数据传输</strong></p></blockquote>',100)])])}const u=l(h,[["render",d]]);export{b as __pageData,u as default};
